<?php
/**
 * Body content translations - bypasses WordPress .mo system for reliable language switching.
 * Uses $_GET['lang'] and cookie directly to avoid cache/locale issues.
 *
 * @package Chess_Podium
 */

if (!defined('ABSPATH')) {
    exit;
}

/** Get current locale from GET/cookie (same logic as plugin, but in theme for body) */
function chess_podium_body_locale(): string {
    $supported = ['en_US', 'it_IT', 'de_DE', 'fr_FR', 'es_ES'];
    if (isset($_GET['lang'])) {
        $lang = sanitize_text_field(wp_unslash($_GET['lang']));
        $map = ['it' => 'it_IT', 'de' => 'de_DE', 'fr' => 'fr_FR', 'es' => 'es_ES', 'en' => 'en_US'];
        $resolved = strlen($lang) === 2 ? ($map[$lang] ?? $lang) : $lang;
        if (in_array($resolved, $supported, true)) {
            return $resolved;
        }
    }
    if (isset($_COOKIE['chess_podium_lang'])) {
        $cookie = sanitize_text_field(wp_unslash($_COOKIE['chess_podium_lang']));
        if (in_array($cookie, $supported, true)) {
            return $cookie;
        }
    }
    return 'en_US';
}

