/** Translate body string - uses GET/cookie directly, bypasses WordPress .mo */
function chess_podium_t(string $text): string {
    $locale = chess_podium_body_locale();
    $strings = chess_podium_body_strings();
    $lang = $strings[$locale] ?? $strings['en_US'] ?? [];
    return $lang[$text] ?? $text;
}

/** Echo translated body string (escaped) */
function chess_podium_te(string $text): void {
    echo esc_html(chess_podium_t($text));
}

/** Return translated string for HTML attribute (escaped) */
function chess_podium_attr_t(string $text): string {
    return esc_attr(chess_podium_t($text));
}
